mapper.select:
SELECT * FROM ( SELECT ROWNUM RN, A.* FROM ( SELECT VA.Volun_Act_No AS volunActNo, VA.Volun_Act_Title AS volunActTitle, O.ORGAN_NAME AS orgName, VA.Volun_Act_Recru_Begin AS volunActRecruBegin, VA.Volun_Act_Recru_End AS volunActRecruEnd, VA.Volun_Act_Proc_Begin AS volunActProcBegin, VA.Volun_Act_Proc_End AS volunActProcEnd, VA.Volun_Act_Point AS volunActPoint, VA.Volun_Act_Address AS volunActAddress,
/* 모집 상태 */ CASE WHEN SYSDATE BETWEEN VA.Volun_Act_Recru_Begin AND VA.Volun_Act_Recru_End THEN '모집중' WHEN SYSDATE < VA.Volun_Act_Recru_Begin THEN '모집예정' ELSE '모집마감' END AS recruStatus,
/* 활동 타입 */ CASE VA.Volun_Act_Act_Type WHEN 1 THEN '환경' WHEN 2 THEN '의료' WHEN 3 THEN '교육' WHEN 4 THEN '생활·편의' WHEN 5 THEN '문화·체육·예술' ELSE '기타' END AS actTypeName,
/* 연령대 */ CASE VA.Volun_Act_Age_Group WHEN 1 THEN '청소년' WHEN 2 THEN '청년' WHEN 3 THEN '직장인' END AS ageGroupName
FROM TBL_VOLUN_ACTIVITY VA LEFT JOIN TBL_ORGAN O ON VA.Volun_Act_Organ_No = O.ORGAN_NO
VA.Volun_Act_Act_Type = #{volunActActType}
AND VA.Volun_Act_Age_Group = #{volunActAgeGroup}
AND SYSDATE BETWEEN VA.Volun_Act_Recru_Begin AND VA.Volun_Act_Recru_End
AND SYSDATE < VA.Volun_Act_Recru_Begin
AND SYSDATE > VA.Volun_Act_Recru_End
AND O.ORGAN_NAME LIKE '%' || #{organization} || '%'
AND VA.Volun_Act_Title LIKE '%' || #{keyword} || '%'
AND VA.Volun_Act_Point = #{keyword}
ORDER BY VA.Volun_Act_No DESC
) A WHERE ROWNUM <= #{endRow} ) WHERE RN > #{startRow}

mapper.update:
UPDATE TBL_VOLUN_APPLY
SET VOLUNACT_APPLYSTATUS = 0
WHERE VOLUN_ACT_NO = #{volunActNo}
  AND USER_NO = #{userNo}
